}
if (metadata["additionalInfo"] != undefined) {
var additionalinfo = JSON.parse(metadata["additionalInfo"]);
}
else {
    additionalinfo = {};
}
details["additionalInfo"] = additionalinfo;
details["additionalInfo"]["interlock_name"] = "Healthiness of Fire Engine";
details["additionalInfo"]["message"] = "Fire Engine in Manual mode";
details["additionalInfo"]["unit_name"] = additionalinfo["PLC Name"];
details["additionalInfo"]["plantlocation"] = metadata["ss_plantlocation"];
details["additionalInfo"]["plantlocationid"] = metadata["ss_plantlocationid"];
details["additionalInfo"]["sap_id"] = metadata["ss_sapid"];
details["additionalInfo"]["bu"] = metadata["ss_BU"];
