details["additionalInfo"]["sop_id"] = "SOP033";
details['additionalInfo']['device_id'] = metadata['deviceId']
details['additionalInfo']['device_name'] = metadata['originatorName']
details['additionalInfo']['device_type'] = metadata["deviceType"]
details['additionalInfo']['customData'] = msg_data
return details;

